// The bot reacts ONLY when it is @mentioned (context.mentions contains the bot
// number) and the message is not its own. The command is the first non-@ word.
const cfg = $('Config').first().json;
const BOT = String(cfg.botNumber || '').replace(/[^0-9]/g, '');
const body = $('WhatsApp Inbound').first().json.body || {};
const msg = (body.messages && body.messages[0]) || {};
const text = (msg.text && msg.text.body) ? String(msg.text.body).trim() : '';
const from = String(msg.from || '').replace(/[^0-9]/g, '');
const chatId = msg.chat_id || '';
const fromMe = msg.from_me === true;
const mentions = (msg.context && Array.isArray(msg.context.mentions)) ? msg.context.mentions.map(m => String(m).replace(/[^0-9]/g, '')) : [];
const isBot = fromMe || (BOT.length > 0 && from === BOT);
const mentioned = !isBot && BOT.length > 0 && mentions.includes(BOT);
const words = text.split(' ').filter(t => t && t.charAt(0) !== '@');
const command = mentioned ? (words[0] || '').toLowerCase() : '';
const targetPlayers = mentions.filter(m => m && m !== BOT);
return [{ json: { mentioned, command, number: from, chatId, text, targetPlayers } }];

// ── sign-in: nickname from the Data Table row → match roster → write participant.
// Confirms exactly what happened (newly signed in vs. already signed in). ──
function normalizeNick(s){return String(s==null?'':s).trim().toLowerCase();}
function sanitizeKey(s){return String(s).replace(/[.$#\[\]\/ -]/g,'_');}
function pickLatestTid(pointer,registry){if(pointer&&typeof pointer==='string')return pointer;let best=null,bo=-Infinity;for(const [id,t] of Object.entries(registry||{})){if(!t||id.startsWith('_'))continue;const o=typeof t.order==='number'?t.order:0;if(o>bo){best=id;bo=o;}}return best;}
function matchRoster(players,nickname){const tgt=normalizeNick(nickname);return (players||[]).find(p=>normalizeNick(p)===tgt)||null;}

const cfg = $('Config').first().json;
const p = $('Parse Message').first().json;
const chatId = p.chatId; const who = '@'+p.number+' '; const M = [p.number];
const q = cfg.fbAuth || '';
const row = ($input.first() && $input.first().json) || {};
const nickname = row.nickname ? String(row.nickname) : '';

async function send(message, mentions){ const b = { to: chatId, body: message }; if(mentions && mentions.length) b.mentions = mentions; if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body: b, json:true }); } return [{ json:{ message } }]; }

if(!nickname){ return await send.call(this, who+'your number is not registered for this tournament.', M); }
const pointer = await this.helpers.httpRequest({ url: cfg.fbUrl+'/latest_tournament.json'+q, json:true }).catch(()=>null);
let tid = (pointer && typeof pointer==='string') ? pointer : null;
if(!tid){ const reg = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments.json'+q, json:true }).catch(()=>({})); tid = pickLatestTid(null, reg||{}); }
if(!tid){ return await send.call(this, who+'there is no active tournament right now.', M); }
const players = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments/'+tid+'/players.json'+q, json:true }).catch(()=>[]);
const match = matchRoster(players, nickname);
if(!match){ return await send.call(this, who+'"'+nickname+'" is not on the player list for '+tid+'.', M); }
const title = (await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments/'+tid+'/title.json'+q, json:true }).catch(()=>null)) || tid;
const pKey = sanitizeKey(match);
const existing = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments/'+tid+'/participants/'+pKey+'.json'+q, json:true }).catch(()=>null);
if(existing && existing.nickname){ return await send.call(this, who+'ℹ️ '+match+' is already signed in to '+title+'.', M); }
const record = { nickname: match, status:'signed_in', joined_at: Date.now(), tournament_id: tid };
await this.helpers.httpRequest({ method:'PUT', url: cfg.fbUrl+'/tournaments/'+tid+'/participants/'+pKey+'.json'+q, body: record, json:true });
return await send.call(this, who+'✅ Signed in! '+match+' is now registered for '+title+'.', M);

// ── help: list the commands, tagging the requester. ──
const cfg = $('Config').first().json;
const p = $('Parse Message').first().json;
const message = '@'+p.number+' Commands (tag me + the word):\n• sign-in — join the current tournament\n• help — show this help\n• start-tournament — begin a tournament (coming soon)\n• defeated @player — report that you beat @player';
const b = { to: p.chatId, body: message, mentions: [p.number] };
if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body: b, json:true }); }
return [{ json:{ sent:'help' } }];

// ── start-tournament: placeholder (to be implemented). ──
const cfg = $('Config').first().json;
const p = $('Parse Message').first().json;
const message = '@'+p.number+' 🚧 start-tournament received — this command is coming soon.';
const b = { to: p.chatId, body: message, mentions: [p.number] };
if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body: b, json:true }); }
return [{ json:{ sent:'start-tournament' } }];

// ── defeated @player: resolve the tagged opponent's number → nickname via the
// Data Table. Result recording comes with start-tournament (placeholder). ──
const cfg = $('Config').first().json;
const p = $('Parse Message').first().json;
const chatId = p.chatId;
const target = (p.targetPlayers && p.targetPlayers[0]) || '';
const row = ($input.first() && $input.first().json) || {};
const oppNick = row.nickname ? String(row.nickname) : '';

async function send(message, mentions){ const b = { to: chatId, body: message }; if(mentions && mentions.length) b.mentions = mentions; if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body: b, json:true }); } return [{ json:{ message } }]; }

if(!target){ return await send.call(this, '@'+p.number+' tag the player you defeated, e.g. "@bot defeated @player".', [p.number]); }
if(!oppNick){ return await send.call(this, '@'+p.number+" I don't recognize @"+target+' as a registered player.', [p.number, target]); }
return await send.call(this, '@'+p.number+' 🚧 got it — you beat @'+target+' ('+oppNick+'). Result recording is coming soon.', [p.number, target]);

// ── default: unrecognized command. ──
const cfg = $('Config').first().json;
const p = $('Parse Message').first().json;
const message = '@'+p.number+' command not recognized. Tag me with "help" to see the commands.';
const b = { to: p.chatId, body: message, mentions: [p.number] };
if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body: b, json:true }); }
return [{ json:{ sent:'not_recognized' } }];
